(11,'2025-08-30 18:16:38','2025-08-30 18:16:38','SISTEMA','comando_token','Indica il codice segreto usato per l\'esecuzione di un comando tramite URL<br>[testo]','',1),
(12,'2025-08-30 18:16:38','2025-08-30 18:16:38','SISTEMA','scarica_competenze','Indica se la certificazione delle competenze, compilata nello scrutinio finale della classe seconda, deve essere scaricabile da alunni e genitori.<br>[formato: S=si, N=no]','N',0),
