(14,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','anno_scolastico','Anno scolastico corrente<br>[formato: AAAA/AAAA]','2022/2023',0),
(15,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','anno_inizio','Data dell\'inizio dell\'anno scolastico<br>[formato: AAAA-MM-GG]','2022-09-14',0),
(16,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','anno_fine','Data della fine dell\'anno scolastico<br>[formato: AAAA-MM-GG]','2023-06-10',0),
(17,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','periodo1_nome','Nome del primo periodo dell\'anno scolastico (primo trimestre/quadrimestre)<br>[testo]','Primo Quadrimestre',0),
(18,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','periodo1_fine','Data della fine del primo periodo, da <em>anno_inizio</em> sino al giorno indicato incluso<br>[formato: AAAA-MM-GG]','2023-01-31',0),
(19,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','periodo2_nome','Nome del secondo periodo dell\'anno scolastico (secondo trimestre/quadrimestre/pentamestre)<br>[testo]','Secondo Quadrimestre',0),
(20,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','periodo2_fine','Data della fine del secondo periodo, da <em>periodo1_fine</em>+1 sino al giorno indicato incluso (se non &egrave; usato un terzo periodo, la data dovr&agrave; essere uguale a <em>anno_fine</em><br>[formato AAAA-MM-GG]','2023-06-10',0),
(21,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','periodo3_nome','Nome del terzo periodo dell\'anno scolastico (terzo trimestre) o vuoto se non usato (se &egrave; usato un terzo periodo, inizia a <em>periodo2_fine</em>+1 e finisce a <em>anno_fine</em><br>[testo]','',0),
(22,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','ritardo_breve','Numero di minuti per la definizione di ritardo breve (non richiede giustificazione)<br>[numero intero]','10',0),
(23,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','mesi_colloqui','Mesi con i colloqui generali, nei quali non si pu&ograve; prenotare il colloquio individuale<br>[lista separata da virgola dei numeri dei mesi]','12,3',0),
(24,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','notifica_circolari','Ora di inizio notifica giornaliera delle nuove circolari<br>[ora in formato HH:MM]','17:00',0),
(25,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','nota_modifica','Indica il numero di minuti entro cui si può modificare una nota; 0 permette la modifica senza limitazioni.<br>[numero intero]','30',0),
(26,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','nota_provvedimento','Indica chi può inserire il provvedimento disciplinare in una nota; a scelta tra: solo lo staff, lo staff e il coordinatore, o il docente che l\'ha inserita, il coordinatore e lo staff;<br>[S = staff, C = coordinatore e staff, D = docente, coordinatore e staff]','S',0),
(27,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','voti_finali_R','Lista dei voti finali per Religione<br>[lista serializzata]','a:8:{s:3:\"min\";i:20;s:3:\"max\";i:27;s:4:\"suff\";i:23;s:3:\"med\";i:23;s:6:\"valori\";s:23:\"20,21,22,23,24,25,26,27\";s:9:\"etichette\";s:36:\"\"NC\",\"\",\"\",\"Suff.\",\"\",\"\",\"\",\"Ottimo\"\";s:4:\"voti\";s:98:\"\"Non Classificato\",\"Insufficiente\",\"Mediocre\",\"Sufficiente\",\"Discreto\",\"Buono\",\"Distinto\",\"Ottimo\"\";s:8:\"votiAbbr\";s:84:\"\"NC\",\"Insufficiente\",\"Mediocre\",\"Sufficiente\",\"Discreto\",\"Buono\",\"Distinto\",\"Ottimo\"\";}',1),
(28,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','voti_finali_E','Lista dei voti finali per Educazione Civica<br>[lista serializzata]','a:8:{s:3:\"min\";i:2;s:3:\"max\";i:10;s:4:\"suff\";i:6;s:3:\"med\";i:5;s:6:\"valori\";s:18:\"2,3,4,5,6,7,8,9,10\";s:9:\"etichette\";s:21:\"\"NC\",3,4,5,6,7,8,9,10\";s:4:\"voti\";s:35:\"\"Non Classificato\",3,4,5,6,7,8,9,10\";s:8:\"votiAbbr\";s:21:\"\"NC\",3,4,5,6,7,8,9,10\";}',1),
(29,'2025-08-30 18:16:38','2025-08-30 18:16:38','SCUOLA','voti_finali_C','Lista dei voti finali per Condotta<br>[lista serializzata]','a:8:{s:3:\"min\";i:4;s:3:\"max\";i:10;s:4:\"suff\";i:6;s:3:\"med\";i:6;s:6:\"valori\";s:14:\"4,5,6,7,8,9,10\";s:9:\"etichette\";s:17:\"\"NC\",5,6,7,8,9,10\";s:4:\"voti\";s:31:\"\"Non Classificato\",5,6,7,8,9,10\";s:8:\"votiAbbr\";s:17:\"\"NC\",5,6,7,8,9,10\";}',1),
